// ExtractText implements mm_usecase.TextExtractor
func (mmExtractText *TextExtractorMock) ExtractText(fileType string, data []byte) (s1 string, err error) {
	mm_atomic.AddUint64(&mmExtractText.beforeExtractTextCounter, 1)
	defer mm_atomic.AddUint64(&mmExtractText.afterExtractTextCounter, 1)

	mmExtractText.t.Helper()

	if mmExtractText.inspectFuncExtractText != nil {
		mmExtractText.inspectFuncExtractText(fileType, data)
	}

	mm_params := TextExtractorMockExtractTextParams{fileType, data}

	// Record call args
	mmExtractText.ExtractTextMock.mutex.Lock()
	mmExtractText.ExtractTextMock.callArgs = append(mmExtractText.ExtractTextMock.callArgs, &mm_params)
	mmExtractText.ExtractTextMock.mutex.Unlock()

	for _, e := range mmExtractText.ExtractTextMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return e.results.s1, e.results.err
		}
	}

	if mmExtractText.ExtractTextMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmExtractText.ExtractTextMock.defaultExpectation.Counter, 1)
		mm_want := mmExtractText.ExtractTextMock.defaultExpectation.params
		mm_want_ptrs := mmExtractText.ExtractTextMock.defaultExpectation.paramPtrs

		mm_got := TextExtractorMockExtractTextParams{fileType, data}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.fileType != nil && !minimock.Equal(*mm_want_ptrs.fileType, mm_got.fileType) {
				mmExtractText.t.Errorf("TextExtractorMock.ExtractText got unexpected parameter fileType, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmExtractText.ExtractTextMock.defaultExpectation.expectationOrigins.originFileType, *mm_want_ptrs.fileType, mm_got.fileType, minimock.Diff(*mm_want_ptrs.fileType, mm_got.fileType))
			}

			if mm_want_ptrs.data != nil && !minimock.Equal(*mm_want_ptrs.data, mm_got.data) {
				mmExtractText.t.Errorf("TextExtractorMock.ExtractText got unexpected parameter data, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmExtractText.ExtractTextMock.defaultExpectation.expectationOrigins.originData, *mm_want_ptrs.data, mm_got.data, minimock.Diff(*mm_want_ptrs.data, mm_got.data))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmExtractText.t.Errorf("TextExtractorMock.ExtractText got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmExtractText.ExtractTextMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		mm_results := mmExtractText.ExtractTextMock.defaultExpectation.results
		if mm_results == nil {
			mmExtractText.t.Fatal("No results are set for the TextExtractorMock.ExtractText")
		}
		return (*mm_results).s1, (*mm_results).err
	}
	if mmExtractText.funcExtractText != nil {
		return mmExtractText.funcExtractText(fileType, data)
	}
	mmExtractText.t.Fatalf("Unexpected call to TextExtractorMock.ExtractText. %v %v", fileType, data)
	return
}

